SELECT EXTRACT(YEAR FROM "DATE_OF_LOSS") AS "YEAR", SUM("BUILDING_DAMAGE_AMOUNT") AS "TOTAL_BUILDING_DAMAGE", SUM("CONTENTS_DAMAGE_AMOUNT") AS "TOTAL_CONTENTS_DAMAGE" FROM "WEATHER__ENVIRONMENT"."CYBERSYN"."FEMA_NATIONAL_FLOOD_INSURANCE_PROGRAM_CLAIM_INDEX" WHERE "NFIP_COMMUNITY_NAME" = 'City Of New York' AND "DATE_OF_LOSS" >= '2010-01-01' AND "DATE_OF_LOSS" <= '2019-12-31' GROUP BY EXTRACT(YEAR FROM "DATE_OF_LOSS") ORDER BY "YEAR"